// ==================== 服务定义 ====================
type BiliGoService interface {
	// 用户模块
	Register(ctx context.Context, req *RegisterReq) (r *RegisterResp, err error)

	Login(ctx context.Context, req *LoginReq) (r *LoginResp, err error)

	GetUserInfo(ctx context.Context, req *UserInfoReq) (r *UserInfoResp, err error)

	UploadAvatar(ctx context.Context, req *UploadAvatarReq) (r *UploadAvatarResp, err error)
	// 视频模块
	PublishVideo(ctx context.Context, req *PublishVideoReq) (r *PublishVideoResp, err error)

	GetVideoList(ctx context.Context, req *VideoListReq) (r *VideoListResp, err error)

	GetPopularVideos(ctx context.Context, req *PopularVideosReq) (r *PopularVideosResp, err error)

	SearchVideo(ctx context.Context, req *SearchVideoReq) (r *SearchVideoResp, err error)
	// 互动模块
	LikeAction(ctx context.Context, req *LikeActionReq) (r *LikeActionResp, err error)

	GetLikeList(ctx context.Context, req *LikeListReq) (r *LikeListResp, err error)

	PublishComment(ctx context.Context, req *PublishCommentReq) (r *PublishCommentResp, err error)

	GetCommentList(ctx context.Context, req *CommentListReq) (r *CommentListResp, err error)

	DeleteComment(ctx context.Context, req *DeleteCommentReq) (r *DeleteCommentResp, err error)
	// 社交模块
	RelationAction(ctx context.Context, req *RelationActionReq) (r *RelationActionResp, err error)

	GetFollowingList(ctx context.Context, req *FollowingListReq) (r *FollowingListResp, err error)

	GetFollowerList(ctx context.Context, req *FollowerListReq) (r *FollowerListResp, err error)

	GetFriendsList(ctx context.Context, req *FriendsListReq) (r *FriendsListResp, err error)
}

